import React, {
  Dispatch,
  memo,
  SetStateAction,
  useCallback,
  useEffect,
  useMemo,
  useState
} from 'react'
import { useDispatch, useSelector } from 'react-redux'
import { SpectionItemParams, SpectionItemReply } from 'api/model/property/spectionItemModel'
import { create, find, update } from 'modules/property/spectionItem'
import {
  Box,
  CircularProgress,
  FormLabel,
  Stack,
  Button,
  TextField,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle,
  MenuItem,
  IconButton
} from '@mui/material'
import message from 'components/Message'
import { buttonStyles } from 'components/DeleteModal'
import { Add, Delete } from '@mui/icons-material'

interface FormDialogProps {
  dialogValue?: SpectionItemReply
  openDialog: boolean
  dialogType: string
  setOpenDialog: Dispatch<SetStateAction<boolean>>
}

const FormDialog: React.FC<FormDialogProps> = ({
  dialogValue,
  openDialog,
  dialogType,
  setOpenDialog
}) => {
  const dispatch = useDispatch<AppDispatch>()
  const { page } = useSelector((state: RootState) => state.SpectionItemSlice)
  const [loading, setLoading] = useState(false)

  const initialFormData = useMemo(
    () => ({
      name: dialogType === 'edit' ? dialogValue?.name || '' : '',
      seq: dialogType === 'edit' ? dialogValue?.seq || 0 : 0,
      titleType: dialogType === 'edit' && dialogValue?.titleType ? dialogValue.titleType : 1,
      spectionItemVal:
        dialogType === 'edit' &&
        Array.isArray(dialogValue?.spectionItemVal) &&
        dialogValue.spectionItemVal.length >= 2
          ? dialogValue.spectionItemVal
          : [
              { itemId: '', itemValue: '' },
              { itemId: '', itemValue: '' }
            ]
    }),
    [dialogType, dialogValue]
  )

  const [formData, setFormData] = useState<SpectionItemParams>(initialFormData)

  useEffect(() => {
    setFormData(initialFormData)
  }, [initialFormData])

  const handleSubmit = useCallback(
    async (event: React.FormEvent<HTMLFormElement>) => {
      event.preventDefault()
      setLoading(true)
      try {
        const current_community = localStorage.getItem('current_community')
        const community = JSON.parse(current_community || '')
        const params = { ...formData, communityId: community?.id }
        const action =
          dialogType === 'add' ? create(params) : update({ id: dialogValue?.id, ...params })
        const res = await dispatch(action)
        if ('error' in res && res.error?.message) {
          throw new Error(res.error.message)
        }
        await dispatch(find({ 'page.num': page.num || '1', 'page.size': page.size }))
        message.success(dialogType === 'add' ? '新建成功' : '编辑成功')
        setOpenDialog(false)
        setFormData(initialFormData)
      } catch (err: unknown) {
        setLoading(false)
        if (err instanceof Error) message.error(err.message)
      } finally {
        setLoading(false)
      }
    },
    [dispatch, dialogType, dialogValue, formData, page, setOpenDialog, initialFormData]
  )

  const addOption = useCallback(() => {
    setFormData(prev => ({
      ...prev,
      spectionItemVal: Array.isArray(prev.spectionItemVal)
        ? [...prev.spectionItemVal, { itemId: '', itemValue: '' }]
        : [
            { itemId: '', itemValue: '' },
            { itemId: '', itemValue: '' }
          ]
    }))
  }, [])

  const deleteOption = useCallback((index: number) => {
    setFormData(prev => {
      if (!Array.isArray(prev.spectionItemVal)) {
        return prev
      }
      const updated = prev.spectionItemVal.filter((_, i) => i !== index)
      return {
        ...prev,
        spectionItemVal: updated.length >= 2 ? updated : prev.spectionItemVal
      }
    })
  }, [])

  const formFields = [
    { label: '题目', type: 'text', id: 'name', required: true },
    { label: '顺序', type: 'number', id: 'seq', required: true }
  ]

  return (
    <Dialog
      fullWidth
      maxWidth="sm"
      open={openDialog}
      onClose={() => setOpenDialog(false)}
      PaperProps={{ component: 'form', onSubmit: handleSubmit }}
    >
      <DialogTitle>{dialogType === 'add' ? '新增' : '编辑'}</DialogTitle>
      <DialogContent dividers sx={{ margin: '0 10px 0' }}>
        <Stack spacing={3}>
          {formFields.map(({ label, type, id, required }) => (
            <Box
              sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}
              key={id}
            >
              <FormLabel>{label}：</FormLabel>
              <TextField
                placeholder="请输入"
                type={type}
                sx={{ width: '80%' }}
                size="small"
                required={required}
                id={id}
                value={formData[id as keyof SpectionItemParams]}
                onChange={e => setFormData({ ...formData, [id]: e.target.value })}
              />
            </Box>
          ))}
          <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
            <FormLabel>题目类型：</FormLabel>
            <TextField
              placeholder="请选择"
              sx={{ width: '80%' }}
              select
              size="small"
              value={formData.titleType}
              onChange={e => setFormData({ ...formData, titleType: Number(e.target.value) })}
              variant="outlined"
            >
              {[
                { value: 1, label: '单选' },
                { value: 2, label: '多选' },
                { value: 3, label: '简答题' }
              ].map(option => (
                <MenuItem key={option.value} value={option.value}>
                  {option.label}
                </MenuItem>
              ))}
            </TextField>
          </Box>
          {formData.titleType !== 3 &&
            formData.titleType !== 0 &&
            formData.spectionItemVal?.map((item, index) => (
              <Box
                key={index + 1}
                sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}
              >
                <Box sx={{ width: '100%', display: 'flex', alignItems: 'center' }}>
                  <FormLabel>选项{index + 1}：</FormLabel>
                  <TextField
                    placeholder="请输入"
                    sx={{
                      width:
                        formData.spectionItemVal && formData.spectionItemVal.length > 2
                          ? '70%'
                          : index === (formData.spectionItemVal?.length ?? 0) - 1
                            ? '75%'
                            : '79.5%',
                      marginLeft: '60px'
                    }}
                    size="small"
                    value={item.itemValue}
                    onChange={e => {
                      if (Array.isArray(formData.spectionItemVal)) {
                        const updatedOptions = [...formData.spectionItemVal]
                        updatedOptions[index].itemValue = e.target.value
                        setFormData({ ...formData, spectionItemVal: updatedOptions })
                      }
                    }}
                    variant="outlined"
                  />
                </Box>
                <Box sx={{ display: 'flex', alignItems: 'center' }}>
                  {index === (formData.spectionItemVal?.length ?? 0) - 1 && (
                    <IconButton aria-label="add" size="medium" onClick={addOption}>
                      <Add fontSize="inherit" />
                    </IconButton>
                  )}
                  {(formData.spectionItemVal?.length ?? 0) > 2 && (
                    <IconButton
                      aria-label="delete"
                      size="medium"
                      sx={{ ml: 1 }}
                      onClick={() => deleteOption(index)}
                    >
                      <Delete fontSize="inherit" />
                    </IconButton>
                  )}
                </Box>
              </Box>
            ))}
        </Stack>
      </DialogContent>
      <DialogActions>
        <Button variant="contained" color="error" onClick={() => setOpenDialog(false)}>
          取消
        </Button>
        <Button
          variant="contained"
          type="submit"
          color="error"
          sx={buttonStyles('#2660ad', '#1d428a')}
          disabled={loading}
          startIcon={loading && <CircularProgress size={24} color="inherit" />}
        >
          {loading ? '保存中...' : '保存'}
        </Button>
      </DialogActions>
    </Dialog>
  )
}

export default memo(FormDialog)
